blocks.body:
{
    "level": "A2–B1",
    "intro": "W tym temacie poznasz <strong>zaimki zwrotne</strong>, ich formy oraz najważniejsze zastosowania. Zobaczysz też różnicę między użyciem zwrotnym a emfatycznym, czyli wzmacniającym.",
    "rules": [
        {
            "label": "-self / -selves",
            "color": "emerald",
            "text": "Formy w liczbie pojedynczej kończą się na <strong>-self</strong>, a w mnogiej na <strong>-selves</strong>.",
            "example": "myself, yourself, himself, herself, itself, ourselves, yourselves, themselves"
        },
        {
            "label": "Użycie zwrotne",
            "color": "blue",
            "text": "Używamy ich, gdy <strong>podmiot wykonuje czynność na sobie samym</strong>.",
            "example": "I hurt myself. / She introduced herself."
        },
        {
            "label": "Użycie emfatyczne",
            "color": "amber",
            "text": "Zaimki zwrotne mogą też <strong>wzmacniać</strong> wypowiedź: podkreślają, kto coś zrobił.",
            "example": "I did it myself. / The manager himself called."
        }
    ]
}

{
    "title": "1. Pełna tabela zaimków zwrotnych",
    "intro": "Oto podstawowe formy zaimków zwrotnych w języku angielskim:",
    "rows": [
        {
            "en": "I → myself",
            "ua": "ja → myself",
            "note": "I hurt myself."
        },
        {
            "en": "you → yourself",
            "ua": "ty → yourself",
            "note": "Did you enjoy yourself?"
        },
        {
            "en": "he → himself",
            "ua": "on → himself",
            "note": "He taught himself to cook."
        },
        {
            "en": "she → herself",
            "ua": "ona → herself",
            "note": "She introduced herself."
        },
        {
            "en": "it → itself",
            "ua": "to → itself",
            "note": "The cat cleaned itself."
        },
        {
            "en": "we → ourselves",
            "ua": "my → ourselves",
            "note": "We enjoyed ourselves."
        },
        {
            "en": "you → yourselves",
            "ua": "wy → yourselves",
            "note": "You did it yourselves."
        },
        {
            "en": "they → themselves",
            "ua": "oni / one → themselves",
            "note": "They blamed themselves."
        }
    ],
    "warning": "📌 <strong>-self</strong> używamy w liczbie pojedynczej, a <strong>-selves</strong> w mnogiej."
}

{
    "title": "2. Użycie zwrotne: działanie na siebie",
    "sections": [
        {
            "label": "Gdy podmiot = dopełnienie",
            "color": "emerald",
            "description": "Zaimka zwrotnego używamy, gdy <strong>ta sama osoba wykonuje czynność i jej doświadcza</strong>.",
            "examples": [
                {
                    "en": "I hurt myself.",
                    "ua": "Zraniłem się."
                },
                {
                    "en": "She cut herself with a knife.",
                    "ua": "Skaleczyła się nożem."
                },
                {
                    "en": "He taught himself to play the guitar.",
                    "ua": "Nauczył się sam grać na gitarze."
                },
                {
                    "en": "We enjoyed ourselves at the party.",
                    "ua": "Świetnie się bawiliśmy na imprezie."
                },
                {
                    "en": "They introduced themselves.",
                    "ua": "Przedstawili się."
                }
            ]
        },
        {
            "label": "Częste czasowniki",
            "color": "sky",
            "description": "Niektóre czasowniki bardzo często występują z zaimkami zwrotnymi.",
            "examples": [
                {
                    "en": "hurt yourself",
                    "ua": "zranić się"
                },
                {
                    "en": "cut yourself",
                    "ua": "skaleczyć się"
                },
                {
                    "en": "teach yourself",
                    "ua": "nauczyć się samemu"
                },
                {
                    "en": "enjoy yourself",
                    "ua": "dobrze się bawić"
                },
                {
                    "en": "introduce yourself",
                    "ua": "przedstawić się"
                },
                {
                    "en": "help yourself",
                    "ua": "częstować się / brać sobie"
                }
            ]
        },
        {
            "label": "Po przyimkach",
            "color": "purple",
            "description": "Zaimki zwrotne pojawiają się też po niektórych przyimkach i w stałych połączeniach.",
            "examples": [
                {
                    "en": "Look at yourself in the mirror.",
                    "ua": "Spójrz na siebie w lustrze."
                },
                {
                    "en": "She sometimes talks to herself.",
                    "ua": "Czasami mówi do siebie."
                },
                {
                    "en": "You should believe in yourself.",
                    "ua": "Powinieneś uwierzyć w siebie."
                },
                {
                    "en": "Learn to laugh at yourself.",
                    "ua": "Naucz się śmiać z samego siebie."
                }
            ]
        }
    ]
}

{
    "title": "3. Użycie emfatyczne: dla podkreślenia",
    "sections": [
        {
            "label": "Dla wzmocnienia",
            "color": "amber",
            "description": "Zaimki zwrotne mogą podkreślać, że <strong>to właśnie ta osoba</strong> wykonała czynność, bez pomocy albo osobiście.",
            "examples": [
                {
                    "en": "I did it myself.",
                    "ua": "Zrobiłem to sam."
                },
                {
                    "en": "She cooked dinner herself.",
                    "ua": "Sama ugotowała obiad."
                },
                {
                    "en": "The president himself came to the event.",
                    "ua": "Na wydarzenie przyszedł sam prezydent."
                },
                {
                    "en": "We built the house ourselves.",
                    "ua": "Sami zbudowaliśmy ten dom."
                }
            ]
        },
        {
            "label": "Pozycja w zdaniu",
            "color": "blue",
            "description": "W użyciu emfatycznym zaimek może stać <strong>po podmiocie</strong> albo <strong>na końcu zdania</strong>.",
            "examples": [
                {
                    "en": "I myself saw it. = I saw it myself.",
                    "ua": "Obie wersje znaczą: „Widziałem to na własne oczy”."
                },
                {
                    "en": "The boss himself called. = The boss called himself.",
                    "ua": "Pierwsza wersja jest poprawna emfatycznie; druga zmienia znaczenie."
                },
                {
                    "en": "She herself told me. = She told me herself.",
                    "ua": "Obie pozycje są możliwe."
                }
            ],
            "note": "📌 W użyciu emfatycznym najbezpieczniej stawiać zaimek po podmiocie albo na końcu zdania."
        },
        {
            "label": "Zwrotne a emfatyczne",
            "color": "purple",
            "description": "W użyciu zwrotnym zaimek jest <strong>potrzebny</strong>, a w emfatycznym tylko <strong>dodaje nacisk</strong>.",
            "examples": [
                {
                    "en": "I hurt myself.",
                    "ua": "Zaimek jest konieczny, bo czynność wraca do podmiotu."
                },
                {
                    "en": "I did it myself.",
                    "ua": "Tu zaimek tylko podkreśla, kto to zrobił."
                }
            ],
            "note": "Bez zaimka w drugim zdaniu sens pozostaje, ale znika nacisk."
        }
    ]
}

{
    "title": "4. By yourself, for yourself, to yourself",
    "sections": [
        {
            "label": "By yourself",
            "color": "emerald",
            "description": "<strong>By yourself</strong> znaczy „samodzielnie” albo „sam / sama”.",
            "examples": [
                {
                    "en": "I fixed it by myself.",
                    "ua": "Naprawiłem to samodzielnie."
                },
                {
                    "en": "She lives by herself.",
                    "ua": "Mieszka sama."
                },
                {
                    "en": "Can you do it by yourself?",
                    "ua": "Czy możesz to zrobić sam?"
                }
            ],
            "note": "📌 W codziennej angielszczyźnie bardzo częste jest też <strong>on your own</strong>."
        },
        {
            "label": "For yourself",
            "color": "blue",
            "description": "<strong>For yourself</strong> oznacza „dla siebie”.",
            "examples": [
                {
                    "en": "Buy something nice for yourself.",
                    "ua": "Kup sobie coś miłego."
                },
                {
                    "en": "Keep some time for yourself.",
                    "ua": "Zostaw sobie trochę czasu."
                },
                {
                    "en": "She made coffee for herself.",
                    "ua": "Zrobiła sobie kawę."
                }
            ]
        },
        {
            "label": "To yourself",
            "color": "sky",
            "description": "<strong>To yourself</strong> pojawia się np. przy mówieniu lub powtarzaniu czegoś w myślach.",
            "examples": [
                {
                    "en": "Keep it to yourself.",
                    "ua": "Zachowaj to dla siebie."
                },
                {
                    "en": "He said to himself that everything would be fine.",
                    "ua": "Powiedział sobie, że wszystko będzie dobrze."
                },
                {
                    "en": "She was whispering to herself.",
                    "ua": "Szeptała coś do siebie."
                }
            ]
        }
    ]
}

{
    "title": "5. Kiedy NIE używamy zaimka zwrotnego",
    "sections": [
        {
            "label": "Po niektórych czasownikach",
            "color": "rose",
            "description": "Niektóre czasowniki w angielskim <strong>nie potrzebują</strong> zaimka zwrotnego, chociaż w innych językach bywa inaczej.",
            "examples": [
                {
                    "en": "I feel tired.",
                    "ua": "Mówimy <strong>feel tired</strong>, nie: <em>feel myself tired</em>."
                },
                {
                    "en": "We met at 5 o'clock.",
                    "ua": "Nie dodajemy tu zaimka zwrotnego."
                },
                {
                    "en": "She got dressed quickly.",
                    "ua": "To naturalna forma bez zaimka zwrotnego."
                }
            ],
            "note": "📌 Uczący się często dodają zaimek tam, gdzie angielski go nie potrzebuje."
        },
        {
            "label": "Wash / dress / shave",
            "color": "amber",
            "description": "Przy czasownikach takich jak <strong>wash</strong>, <strong>dress</strong> czy <strong>shave</strong> zaimek zwrotny bywa możliwy, ale często go pomijamy.",
            "examples": [
                {
                    "en": "He shaved before work.",
                    "ua": "To naturalne zdanie bez zaimka zwrotnego."
                },
                {
                    "en": "The child can wash himself now.",
                    "ua": "Tutaj zaimek jest możliwy, bo chcemy to wyraźnie podkreślić."
                },
                {
                    "en": "She dressed quickly.",
                    "ua": "Forma bez zaimka brzmi naturalnie."
                }
            ]
        },
        {
            "label": "Gdy dopełnienie to ktoś inny",
            "color": "purple",
            "description": "Jeśli działanie dotyczy <strong>innej osoby</strong>, nie używamy zaimka zwrotnego.",
            "examples": [
                {
                    "en": "She washed the child.",
                    "ua": "Umyła dziecko, a nie siebie."
                },
                {
                    "en": "She washed herself.",
                    "ua": "Tutaj dopełnienie odnosi się do niej samej."
                },
                {
                    "en": "He hurt his friend.",
                    "ua": "Zranił kolegę, więc nie używamy zaimka zwrotnego."
                },
                {
                    "en": "He hurt himself.",
                    "ua": "Tu dopełnienie odnosi się do niego samego."
                }
            ]
        }
    ]
}

{
    "title": "6. Zaimki wzajemne a zwrotne",
    "sections": [
        {
            "label": "Each other a zaimki zwrotne",
            "color": "blue",
            "description": "<strong>Each other / one another</strong> opisują działanie wzajemne, a zaimki zwrotne działanie skierowane na siebie.",
            "examples": [
                {
                    "en": "They love each other.",
                    "ua": "Oni się kochają."
                },
                {
                    "en": "They love themselves.",
                    "ua": "Każde z nich kocha samego siebie."
                },
                {
                    "en": "We help each other.",
                    "ua": "Pomagamy sobie nawzajem."
                },
                {
                    "en": "I blame myself.",
                    "ua": "Obwiniam siebie."
                }
            ],
            "note": "📌 To jedno z najczęstszych miejsc, w których uczący się mylą znaczenie."
        },
        {
            "label": "Przykłady różnicy",
            "color": "sky",
            "description": "Porównaj zdania, aby zobaczyć zmianę znaczenia:",
            "examples": [
                {
                    "en": "We see each other often.",
                    "ua": "Często się widujemy."
                },
                {
                    "en": "I see myself in the mirror.",
                    "ua": "Widzę siebie w lustrze."
                },
                {
                    "en": "They looked at each other.",
                    "ua": "Spojrzeli na siebie nawzajem."
                },
                {
                    "en": "She looked at herself.",
                    "ua": "Spojrzała na siebie."
                }
            ]
        }
    ]
}

{
    "title": "7. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Dodawanie zaimka zwrotnego tam, gdzie nie jest potrzebny.",
            "wrong": "I feel myself tired.",
            "right": "✅ I feel tired."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Użycie zaimka zwrotnego po meet.",
            "wrong": "They met themselves at the station.",
            "right": "✅ They met at the station."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Mylenie each other i zaimków zwrotnych.",
            "wrong": "They love themselves. (gdy chodzi o siebie nawzajem)",
            "right": "✅ They love each other."
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Pomijanie zaimka, gdy jest potrzebny.",
            "wrong": "He taught to play the piano.",
            "right": "✅ He taught himself to play the piano."
        }
    ]
}

{
    "title": "9. Ćwiczenia",
    "select_title": "Ćwiczenie 1. Wybierz poprawną formę",
    "select_intro": "Wybierz właściwy zaimek zwrotny albo zdecyduj, że nie jest potrzebny.",
    "selects": [
        {
            "label": "I hurt ___ while cooking. (me / myself)",
            "prompt": "Która forma pasuje?"
        },
        {
            "label": "She taught ___ Spanish. (her / herself)",
            "prompt": "Która forma pasuje?"
        },
        {
            "label": "We enjoyed ___ at the party. (us / ourselves)",
            "prompt": "Która forma pasuje?"
        },
        {
            "label": "I feel ___ tired today. (— / myself)",
            "prompt": "Czy zaimek jest potrzebny?"
        },
        {
            "label": "They met ___ at the station. (— / themselves)",
            "prompt": "Czy zaimek jest potrzebny?"
        }
    ],
    "options": [
        "myself",
        "yourself",
        "himself",
        "herself",
        "ourselves",
        "themselves",
        "—"
    ],
    "input_title": "Ćwiczenie 2. Uzupełnij zdania",
    "input_intro": "Wpisz poprawny zaimek zwrotny.",
    "inputs": [
        {
            "before": "He introduced ___ to the group.",
            "after": " →"
        },
        {
            "before": "Please help ___ to some cake.",
            "after": " →"
        },
        {
            "before": "Look at ___ in the mirror.",
            "after": " →"
        },
        {
            "before": "We did it all by ___.",
            "after": " →"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błędy",
    "rephrase_intro": "Znajdź i popraw błąd z użyciem zaimków zwrotnych.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "I feel myself fine.",
            "example_target": "I feel fine."
        },
        {
            "original": "1. They met themselves at the station.",
            "placeholder": "Popraw zdanie"
        },
        {
            "original": "2. He taught to play the piano.",
            "placeholder": "Popraw zdanie"
        },
        {
            "original": "3. They love themselves. (meaning: each other)",
            "placeholder": "Popraw zdanie"
        }
    ]
}

{
    "title": "Kontynuuj naukę",
    "items": [
        {
            "label": "Zaimki",
            "current": false
        },
        {
            "label": "Osobowe i dopełnieniowe",
            "current": false
        },
        {
            "label": "Formy dzierżawcze",
            "current": false
        },
        {
            "label": "Zaimki nieokreślone",
            "current": false
        },
        {
            "label": "Zaimki zwrotne",
            "current": true
        }
    ]
}
